from dataclasses import dataclass, field
from typing import Optional
import statistics

@dataclass
class ScoringCriterion:
    id: str
    name: str
    dimension: str  # technical | security | commercial | ecosystem
    weight: float   # fraction of dimension total (sum per dimension = 1.0)
    description: str
    rubric: dict[int, str]  # score -> description (e.g., {1: "No capability", 5: "Best-in-class"})

@dataclass
class VendorScore:
    vendor_id: str
    criterion_id: str
    evaluator_id: str
    score: int  # 1-5
    notes: str = ""

@dataclass
class VendorScoringResult:
    vendor_id: str
    composite_score: float
    dimension_scores: dict[str, float]
    criterion_scores: dict[str, float]
    disagreements: list[str] = field(default_factory=list)  # criteria with high variance

class VendorScoringFramework:
    DIMENSION_WEIGHTS = {
        "technical":   0.25,
        "security":    0.20,
        "commercial":  0.20,
        "ecosystem":   0.35,
    }

    def __init__(self, criteria: list[ScoringCriterion]):
        self.criteria = {c.id: c for c in criteria}

    def score_vendors(
        self, scores: list[VendorScore], disagreement_threshold: float = 1.5
    ) -> dict[str, VendorScoringResult]:
        vendors = {s.vendor_id for s in scores}
        results = {}
        for vendor_id in vendors:
            vendor_scores = [s for s in scores if s.vendor_id == vendor_id]
            criterion_scores: dict[str, float] = {}
            disagreements: list[str] = []

            for cid, criterion in self.criteria.items():
                crit_scores = [s.score for s in vendor_scores if s.criterion_id == cid]
                if not crit_scores:
                    criterion_scores[cid] = 0.0
                    continue
                avg = statistics.mean(crit_scores)
                criterion_scores[cid] = avg
                if len(crit_scores) > 1:
                    stddev = statistics.stdev(crit_scores)
                    if stddev > disagreement_threshold:
                        disagreements.append(f"{criterion.name} (stddev={stddev:.1f})")

            dimension_scores: dict[str, float] = {}
            for dimension in self.DIMENSION_WEIGHTS:
                dim_criteria = [c for c in self.criteria.values() if c.dimension == dimension]
                if not dim_criteria:
                    dimension_scores[dimension] = 0.0
                    continue
                dim_score = sum(
                    criterion_scores.get(c.id, 0.0) * c.weight for c in dim_criteria
                )
                dimension_scores[dimension] = dim_score

            composite = sum(
                dimension_scores[dim] * weight
                for dim, weight in self.DIMENSION_WEIGHTS.items()
            )
            results[vendor_id] = VendorScoringResult(
                vendor_id=vendor_id,
                composite_score=composite,
                dimension_scores=dimension_scores,
                criterion_scores=criterion_scores,
                disagreements=disagreements,
            )
        return results

    def ranking(self, results: dict[str, VendorScoringResult]) -> list[tuple[str, float]]:
        return sorted(results.items(), key=lambda x: x[1].composite_score, reverse=True)
